// client/src/pages/MyOrders.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import "./MyOrders.css";

function MyOrders() {
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));
    if (!user || !user.email) {
      alert("Please login to view your orders");
      return;
    }
    axios
      .get(`http://localhost:5000/api/orders/${user.email}`)
      .then((res) => setOrders(res.data))
      .catch((err) => console.error("❌ Fetch orders error:", err));
  }, []);

  if (!orders.length) {
    return <h2 style={{ textAlign: "center", marginTop: "40px" }}>No orders found</h2>;
  }

  return (
    <div className="orders-container">
      <h2>My Orders</h2>
      {orders.map((order) => (
        <div key={order._id} className="order-card">
          <h3>Order ID: {order.orderId}</h3>
          <p><strong>Date:</strong> {new Date(order.createdAt).toLocaleString()}</p>
          <p><strong>Status:</strong> {order.status} | <strong>Payment:</strong> {order.paymentStatus}</p>
          <p><strong>Shipping:</strong> {order.customer.name}, {order.customer.phone}</p>
          <p>{order.customer.address}</p>
          <h4>Items:</h4>
          <ul>
            {order.items.map((item, idx) => (
              <li key={idx}>
                {item.name} ({item.selectedSize}) × {item.quantity} — ₹{item.price * item.quantity}
              </li>
            ))}
          </ul>
          <p><strong>Total Paid:</strong> ₹{order.totals.grandTotal}</p>
        </div>
      ))}
    </div>
  );
}

export default MyOrders;
